&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_36&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_36&#34;&gt; &lt;a href=&#34;https://zh.cppreference.com/w/cpp/numeric/math/exp&#34;&gt; &lt;code&gt;exp()&lt;/code&gt; &lt;/a&gt;&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_37&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_37&#34;&gt; &lt;a href=&#34;https://zh.cppreference.com/w/cpp/numeric/math/log&#34;&gt; &lt;code&gt;log()&lt;/code&gt; &lt;/a&gt; /  &lt;code&gt;log10()&lt;/code&gt;  /  &lt;code&gt;log2()&lt;/code&gt; &lt;/label&gt;&lt;/li&gt;
