&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_39&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_39&#34;&gt; &lt;a href=&#34;https://zh.cppreference.com/w/cpp/numeric/math/sqrt&#34;&gt; &lt;code&gt;sqrt()&lt;/code&gt; &lt;/a&gt;&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_40&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_40&#34;&gt;  &lt;code&gt;sin()&lt;/code&gt;  /  &lt;code&gt;cos()&lt;/code&gt;  /  &lt;code&gt;tan()&lt;/code&gt; &lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_41&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_41&#34;&gt;  &lt;code&gt;asin()&lt;/code&gt;  /  &lt;code&gt;acos()&lt;/code&gt;  /  &lt;code&gt;atan()&lt;/code&gt; &lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_42&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_42&#34;&gt;  &lt;code&gt;sinh()&lt;/code&gt;  /  &lt;code&gt;cosh()&lt;/code&gt;  /  &lt;code&gt;tanh()&lt;/code&gt; &lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_43&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_43&#34;&gt;  &lt;code&gt;asinh()&lt;/code&gt;  /  &lt;code&gt;acosh()&lt;/code&gt;  /  &lt;code&gt;atanh()&lt;/code&gt;  C++11&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_44&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_44&#34;&gt; &lt;a href=&#34;https://zh.cppreference.com/w/cpp/numeric/math/ceil&#34;&gt; &lt;code&gt;ceil()&lt;/code&gt; &lt;/a&gt; / &lt;a href=&#34;https://zh.cppreference.com/w/cpp/numeric/math/floor&#34;&gt; &lt;code&gt;floor()&lt;/code&gt; &lt;/a&gt;&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_45&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_45&#34;&gt; &lt;a href=&#34;https://zh.cppreference.com/w/cpp/numeric/math/round&#34;&gt; &lt;code&gt;round()&lt;/code&gt; &lt;/a&gt; C++11&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数值算法 numeric&lt;/p&gt;
&lt;ul class=&#34;task-list&#34;&gt;
